from flask import Flask, Response
import redis
app = Flask(__name__)


@app.route('/cache')
def get_cache():
    r = redis.Redis(host='localhost', port=11211)

    key = 'count'
    val = 0

    cached_count = r.get('count').decode()

    if not cached_count:
        count = 1

        r.setex(key, val + 1, 3600)

        response = Response('{"count": %s}' % (r.get(key).decode(),), mimetype='application/json')
    else: 
        count += 1
        print('Cache hit')
        response = Response('{"count": "%s"}' % (cached_count,), mimetype='application/json')

    return response